mapper.select:
SELECT COUNT(company_no) AS reviewCount 
FROM review r 
WHERE r.is_paid = 1 AND updated = 1 
AND r.company_no = (
	SELECT company_no FROM company c WHERE user_id = #{userId}
)

SELECT COUNT(company_no) AS reviewCount 
FROM review r 
WHERE r.is_paid = 0 AND updated = 1 
AND r.company_no = (
	SELECT company_no FROM company c WHERE user_id = #{userId}
)
